import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const hellenisticFoundationPhilosopherArticles:Record<string,ArticleSection[]>={
  pyrrho:[
    section('overview','A founder known through the tradition that followed him',[
      'Pyrrho of Elis occupies an unusual place in philosophy: he lends his name to Pyrrhonian skepticism, yet he wrote nothing and cannot safely be treated as the author of the skeptical system preserved centuries later by Sextus Empiricus. Ancient reports present a life marked by unusual composure, indifference to conventional judgments, and freedom from disturbance. They also disagree about what, if anything, Pyrrho taught concerning reality, knowledge, or action. He is therefore both a historical thinker and a symbolic founder constructed by later skeptical memory.',
      'The difficulty is philosophically revealing. Pyrrhonian skepticism warns against assent that exceeds appearances, and Pyrrho himself appears only through evidence that demands precisely such caution. Readers must compare anecdotes, hostile summaries, fragments from his follower Timon, and later skeptical appropriations without turning uncertainty into either confident biography or complete silence. What emerges is not merely “the first skeptic,” but an experiment in how loosening judgment might transform a life before skepticism became an elaborately articulated argumentative practice.'
    ],['skepticism','ancient-greek','ethics'],['pyrrho','sextus-empiricus'],[]),
    section('source-problem','Historical obscurity and the source problem',[
      'Pyrrho lived roughly from 360 to 270 BCE and came from Elis in the northwestern Peloponnese. Nearly every important claim about him arrives through later authors. Diogenes Laertius preserves biography and anecdotes; Eusebius transmits a report from Aristocles criticizing Pyrrho; Sextus presents a later school bearing his name; and fragments associated with Timon offer glimpses filtered through poetry and discipleship. These sources differ in date, purpose, and philosophical allegiance, so agreement among them cannot be assumed.',
      'Anecdotes describe Pyrrho remaining calm in danger, disregarding convention, or relying on friends to navigate ordinary life. Some stories were already challenged in antiquity, and many resemble literary portraits designed to embody a doctrine. They may reveal how Pyrrho’s followers understood tranquility more reliably than what happened on a particular road or ship. Historical reconstruction therefore asks two questions at once: what can be responsibly said about Pyrrho, and why did later writers find these images useful for presenting skepticism as a way of life?',
      'The sources also speak from different moments in a changing debate. A hostile Peripatetic summary may sharpen claims so they can be refuted; a disciple may turn admiration into exemplary biography; a later Pyrrhonist may recognize an ancestor through concepts developed long after his death. Historians cannot simply average these reports. They compare vocabulary, genre, chronology, and argumentative purpose, then mark conclusions by degree of confidence. This layered method keeps Pyrrho historically meaningful without pretending that every later feature of Pyrrhonism was already present in Elis.'
    ],['skepticism','ancient-greek'],['pyrrho','sextus-empiricus'],[]),
    section('timon','Timon of Phlius and the making of Pyrrho’s image',[
      'Timon of Phlius was Pyrrho’s most important early follower and the principal mediator of his reputation. Timon wrote poetry and prose, including satirical verses that attacked dogmatic philosophers and praised Pyrrho’s freedom from their disputes. Only fragments survive, usually quoted by later authors. Through Timon, Pyrrho becomes less the founder of a technical school than an exemplary figure whose disposition exposes the anxiety, vanity, and contradiction produced by claims to wisdom.',
      'The relationship between teacher and interpreter remains uncertain. Timon may systematize suggestions that Pyrrho lived rather than argued, and later sources may read Timon’s formulations back into the teacher. His literary strategy also matters: satire can undermine philosophical pretension without offering a rival treatise, while praise can idealize a life beyond historical recognition. Timon makes Pyrrho durable by giving skepticism a memorable character, but he also ensures that the founder reaches later readers through an already crafted philosophical portrait.'
    ],['skepticism','ancient-greek'],['pyrrho'],[]),
    section('alexander-india','Alexander’s campaign and cautious claims about India',[
      'Ancient reports say Pyrrho accompanied Alexander’s expedition and encountered Indian gymnosophists and Persian Magi. This possibility has encouraged proposals that Indian philosophical traditions influenced his thought. The journey would have exposed a Greek participant to unfamiliar practices and claims about life, discipline, and reality. It may also have intensified awareness that customs and authoritative beliefs differ across communities, a recurring source of skeptical pressure.',
      'The evidence does not identify which people Pyrrho met, what they taught, or whether a particular doctrine traveled into his philosophy. Broad similarities between Pyrrhonism and Indian traditions cannot establish direct influence, especially when both sides contain diverse positions. The responsible conclusion is modest: contact is historically possible and intellectually suggestive, but detailed stories of transmission remain speculative. Caution here is not evasive. It applies the evidential discipline appropriate to a thinker whose life is already obscured by later construction.'
    ],['skepticism','ancient-greek','indian-philosophy'],['pyrrho'],[]),
    section('aristocles-passage','What are things like? The disputed Aristocles passage',[
      'The most consequential report associates Pyrrho, through Timon, with three questions: what things are like by nature, what attitude people should adopt toward them, and what follows for those who adopt it. The transmitted answer uses difficult Greek terms often rendered as things being indifferent, unstable, or indeterminate, followed by counsel not to trust sensations and opinions and by a promise of freedom from assertion and disturbance. Nearly every part of the passage is debated.',
      'One interpretation makes Pyrrho a metaphysical dogmatist who claims reality itself is indeterminate. Another reads the passage epistemically: things are undecidable for us, so judgment should not settle their nature. Still another emphasizes practical disposition over theory. The dispute determines whether Pyrrho resembles later Pyrrhonists, who suspend claims about how things really are, or advances a doctrine they would also question. It illustrates why no single compact formula can remove the source problem.'
    ],['skepticism','epistemology','metaphysics'],['pyrrho','sextus-empiricus'],[]),
    section('appearances-judgment','Appearances, judgment, and the possibility of tranquility',[
      'Later Pyrrhonism distinguishes what appears from claims about what is true by nature. Honey appears sweet, pain hurts, and a road seems to lead in a direction; the skeptic need not deny these experiences. Disturbance grows when appearances are joined to dogmatic judgments that an external thing is inherently good, evil, or known with certainty. Pyrrho’s remembered composure made him a fitting ancestor for this distinction even though the precise concepts used by Sextus cannot simply be attributed to him.',
      'Tranquility in this setting is not produced by proving a reassuring theory. It follows from releasing the demand to settle what remains uncertain. That release may change fear, ambition, resentment, and attachment to reputation because these often rely on confident value judgments. Yet Pyrrho’s alleged indifference raises practical and ethical questions. If detachment becomes disregard for danger or responsibility, it is difficult to distinguish freedom from negligence. Later skeptics answer by emphasizing ordinary appearances, customs, and skills as guides for action.'
    ],['skepticism','ethics','epistemology'],['pyrrho','sextus-empiricus'],[]),
    section('later-pyrrhonism','Pyrrho himself and later Pyrrhonism',[
      'The skeptical movement associated with Pyrrho did not develop as an uninterrupted institution comparable to the Academy or Stoa. Aenesidemus, working centuries later, is commonly credited with reviving or reshaping Pyrrhonism in opposition to what he saw as the Academy’s movement toward positive doctrines. Agrippa or an Agrippan tradition supplied influential modes concerning disagreement, regress, relativity, hypothesis, and circularity. Sextus Empiricus eventually preserved the most extensive surviving presentation.',
      'This history means that “Pyrrho taught suspension of judgment through the modes” is too simple. The modes and Sextus’ careful vocabulary belong to later argumentative developments. Pyrrho contributes a name, an exemplary life, and perhaps an orientation toward non-assertion and tranquility. Later Pyrrhonists make that orientation into a flexible practice able to confront logic, physics, ethics, and specialized disciplines. Their fidelity lies less in repeating recoverable doctrines than in presenting Pyrrho as a predecessor who refused dogmatic confidence.',
      'The gap between founder and mature school is not merely a defect in the evidence. It shows how a philosophical identity can persist through reinterpretation. Later skeptics could preserve the ethical force of Pyrrho’s example while inventing new argumentative tools for different opponents. Calling the result Pyrrhonism claims continuity, but it also invites readers to distinguish an inherited orientation from the historical stages through which that orientation became a tradition.'
    ],['skepticism','epistemology'],['pyrrho','sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('academic-comparison','Pyrrho and Academic Skepticism',[
      'Academic Skepticism arose inside Plato’s Academy through figures such as Arcesilaus and Carneades. It developed sustained arguments against Stoic claims that some impressions provide a secure criterion of truth. Academic skeptics debated whether knowledge is impossible, whether assent should always be withheld, and what practical standard can guide action. Pyrrho’s remembered approach appears less institutionally dialectical and more closely tied to a disposition or way of life, although the evidence is too uneven for a sharp original contrast.',
      'Later Pyrrhonists distinguished themselves by suspending judgment even about the negative claim that knowledge is impossible. Sextus portrays the Academic who asserts unknowability as a dogmatist of a negative kind, while the Pyrrhonist continues inquiry. Historians dispute whether this fairly represents every Academic. Pyrrho becomes useful in this rivalry because his obscurity permits later skeptics to imagine a more radical refusal of doctrine. The comparison shows traditions defining themselves not only through arguments but through competing stories of philosophical ancestry.',
      'The practical problem sharpens the comparison. Arcesilaus is reported to have appealed to what is reasonable, and Carneades developed the idea of persuasive appearances, as guides that permit action without Stoic certainty. Later Pyrrhonists describe following appearances, customs, and skills while suspending judgment about hidden nature. These answers may overlap more than school polemic admits. Their differences concern not simply whether skeptics can act, but whether a practical criterion becomes a positive commitment. Pyrrho’s remembered life supplies an image of action without theoretical security, even though the historical details remain disputed.'
    ],['skepticism','platonism','stoicism'],['pyrrho','sextus-empiricus','zeno'],[]),
    section('socratic-therapy','Socratic ignorance and Hellenistic therapy',[
      'Pyrrho can be compared with Socratic ignorance because both unsettle people who confidently claim knowledge. Socrates examines definitions and often ends in acknowledged perplexity, while refusing to identify wisdom with reputation or technical display. Pyrrho’s remembered stance similarly makes non-assertion a source of freedom from pretension. The comparison has limits: Socratic inquiry carries strong ethical commitments and public questioning, whereas Pyrrho’s philosophical activity is far harder to reconstruct.',
      'Within Hellenistic philosophy, Pyrrho belongs to a wider effort to make argument therapeutic. Epicureans remove fear through atomism and disciplined desire; Stoics correct judgments through doctrines of virtue and rational nature; skeptics seek release by balancing claims until assent is suspended. Pyrrho symbolizes the possibility that peace does not require discovering a final account. That possibility is both attractive and unsettling, because it asks whether the theories designed to cure anxiety may themselves preserve it through the urgency of defending them.'
    ],['skepticism','ethics','stoicism','epicureanism'],['pyrrho','socrates','epicurus','zeno'],[]),
    section('doctrines-disputes','Did Pyrrho have doctrines?',[
      'Interpreters divide over whether Pyrrho held philosophical doctrines. A doctrinal reading treats the Aristocles report as evidence for claims about the indeterminate nature of things and a consequent ethical stance. A non-doctrinal reading emphasizes suspension, refusing to attribute metaphysical assertions that later Pyrrhonism would undermine. Biographical readings focus on a lived disposition, while other approaches see Timon and later writers constructing coherence from limited materials.',
      'The disagreement cannot be settled by appealing to Pyrrho’s own words because none survive. It instead requires judgments about source reliability, terminology, historical development, and the relation between life and argument. This makes Pyrrho an especially appropriate test case for skeptical historiography. Readers must form responsible provisional conclusions while recognizing that the evidence may not warrant a final one. The founder’s ambiguity is not a blank to fill with preferred doctrines; it is part of what his reception teaches about intellectual restraint.'
    ],['skepticism','epistemology'],['pyrrho','sextus-empiricus'],[]),
    section('legacy-reading','Symbolic founder and how to read Pyrrho',[
      'Pyrrho’s later importance exceeds what can be securely reconstructed about his positions. His name authorizes a skeptical practice that differs from dogmatic denial, and his portrayed life gives suspension an ethical and emotional dimension. Sextus and later readers can point to Pyrrho as evidence that skepticism is not only an argument used against an opponent but a way of inhabiting uncertainty. Modern historians, meanwhile, use him to examine how schools create founders through selective memory.',
      'Begin with the reports collected in a reliable history of Hellenistic philosophy, keeping Timon, Aristocles, Diogenes Laertius, and Sextus distinct. Read the Aristocles passage alongside competing interpretations rather than as a transparent manifesto. Then study Sextus to understand what later Pyrrhonism became without projecting it backward unchanged. The most useful question is not simply what Pyrrho believed. It is how an obscure life came to represent inquiry without dogmatic settlement, and what is gained or lost when a tradition makes that image its beginning.',
      'Pyrrho also clarifies a tension within every philosophy organized around a founder. An exemplary person can make an abstract possibility vivid, but admiration can harden into authority. Skepticism especially risks contradiction if reverence for its founder discourages examination. The strongest reception of Pyrrho therefore treats his image as an invitation rather than a command: test whether withheld assent changes disturbance, remain alert to the practical costs of detachment, and keep conclusions proportionate to evidence. A founder of inquiry is honored most consistently when his own portrait remains open to inquiry.'
    ],['skepticism','ancient-greek'],['pyrrho','sextus-empiricus'],['Outlines of Pyrrhonism'])
  ],
  'sextus-empiricus':[
    section('overview','The writer through whom Pyrrhonism survives',[
      'Sextus Empiricus is the major surviving author of Pyrrhonian skepticism. His works preserve a practice of opposing appearances and arguments, discovering comparable persuasive force, and suspending judgment where inquiry does not justify assent. Sextus does not present skepticism as the conclusion that truth is impossible or that evidence does not matter. The skeptic continues investigating, uses arguments provisionally, and reports how matters presently appear without converting those reports into doctrines about reality.',
      'This distinction gives his writing unusual reflexivity. A skeptical argument must counter dogmatism without becoming another dogma; a formula such as “I suspend judgment” must describe a present condition without claiming universal necessity. Sextus compares skeptical arguments to medicines that can be discarded after treating the disturbance. His books therefore function both as an archive of philosophical controversy and as exercises designed to loosen the compulsion to make unsupported claims.'
    ],['skepticism','epistemology','ancient-greek'],['sextus-empiricus','pyrrho'],['Outlines of Pyrrhonism']),
    section('life-medicine','Physician, empiricist, and elusive author',[
      'Little is securely known about Sextus’ life. He probably wrote in the late second or early third century CE and was associated with medicine, as the name Empiricus suggests. Ancient medical schools disputed how physicians should reason from experience, causes, and hidden processes. Skeptical attention to appearances and resistance to claims about non-evident causes fits some empirical medical concerns, although scholars debate Sextus’ precise medical affiliation.',
      'The medical setting helps clarify skepticism as therapy. Arguments are not valued only as abstract demonstrations; they address disturbances generated by dogmatic commitment. A strong conviction may require a strong counterargument, while a weaker one may need a lighter remedy. This does not mean Sextus treats truth as irrelevant or merely manipulates emotion. The therapeutic comparison explains why arguments with different premises can be useful without being endorsed as final descriptions of reality. Their role is to restore inquiry where premature certainty has closed it.'
    ],['skepticism','epistemology'],['sextus-empiricus'],[]),
    section('outlines','The architecture of the Outlines of Pyrrhonism',[
      'The Outlines of Pyrrhonism begins by distinguishing kinds of philosopher. Dogmatists claim to have discovered truth; Academic skeptics are presented as claiming it cannot be discovered; Pyrrhonists continue searching. Book I explains skeptical ability, suspension, tranquility, modes, and differences from neighboring positions. Books II and III turn skeptical argument toward logic, criteria, signs, proof, causation, physics, theology, and ethics. The movement shows skepticism operating across a philosophical system rather than announcing one objection and stopping.',
      'The work is introductory but not simple. Sextus repeatedly marks the non-dogmatic force of his language, using phrases such as “it appears to me now” or “I determine nothing.” He assembles arguments whose assumptions may conflict because the skeptic need not endorse them all. Readers trained to identify an author’s settled theory can mistake this method for inconsistency. The Outlines instead asks whether opposed theoretical resources can reveal that a question remains unsettled, permitting suspension without a new conclusion about what must be true.'
    ],['skepticism','logic','epistemology'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('against-learned','Against the Mathematicians and specialized expertise',[
      'The collection conventionally called Against the Mathematicians or Against the Learned includes attacks on grammarians, rhetoricians, geometers, arithmeticians, astrologers, musicians, logicians, physicists, and ethicists. The title uses mathematics in an older sense connected with disciplines of learning. Sextus examines whether these fields possess secure principles, criteria, or objects as their dogmatic defenders claim. His target is not every practical skill, but pretensions to theoretical foundations that outrun appearances and established practice.',
      'These works preserve extensive information about ancient positions that might otherwise be lost. Sextus is therefore a major historical source even when his presentation serves skeptical purposes. His arguments can expose circular definitions, disputed starting points, and transitions from observed practice to hidden entities. Yet they also raise a challenge: if grammar, logic, or proof is undermined too thoroughly, how can skeptical writing proceed? Sextus answers pragmatically through ordinary language and non-dogmatic use, but the pressure remains central to interpreting him.'
    ],['skepticism','epistemology','logic'],['sextus-empiricus'],['Against the Mathematicians']),
    section('equipollence-suspension','Equipollence and suspension of judgment',[
      'Sextus defines skepticism as an ability to set appearances and thoughts in opposition in any way, leading through equal persuasive force to suspension and then tranquility. Equipollence does not assert that arguments are objectively equal by nature. It describes how they strike the investigator when no decisive reason establishes one over another. Suspension, epoché, follows not as a chosen doctrine but as the mind’s inability to assent under balanced pressure.',
      'This sequence differs from casual indecision. The skeptic actively investigates, constructs objections, compares contexts, and tests proposed criteria. Suspension is earned through argument rather than adopted before evidence appears. It also remains revisable: further inquiry may change how matters appear. Sextus’ skepticism therefore preserves openness while refusing the demand that inquiry must end with a theory. Critics ask whether judging arguments equipollent already requires standards that the skeptic must defend. That objection keeps the practice answerable to its own stated restraint.'
    ],['skepticism','epistemology','logic'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('modes','The modes as reusable engines of doubt',[
      'The skeptical modes organize recurring ways in which claims lose their appearance of necessity. The ten modes associated with Aenesidemus emphasize variation among animals, people, senses, bodily conditions, positions, mixtures, quantities, and customs. If an object appears differently under different conditions, the dogmatist must justify why one appearance reveals its nature. The modes do not prove that no answer exists; they block unargued privilege.',
      'The five modes associated with Agrippa focus on disagreement, infinite regress, relativity, hypothesis, and circular reasoning. A disputed claim needs support; support can provoke another demand; stopping at an unsupported assumption appears arbitrary; and mutual support risks circularity. These patterns remain influential because they expose structural problems in justification independent of a particular doctrine. Sextus uses them flexibly rather than as a single formal proof, adjusting opposition to whatever confidence confronts him.',
      'A mode is best understood as a diagnostic question, not a machine that automatically defeats every claim. Disagreement may be shallow, a regress may stop with well-supported evidence, and relations among beliefs need not be viciously circular. The skeptical force appears when a claimant cannot explain why the proposed stopping point deserves authority. Using the modes responsibly therefore requires attention to the actual strength of evidence and replies. Their educational value lies in making hidden justificatory choices visible, after which inquiry may suspend, revise, or sometimes proceed with greater confidence.'
    ],['skepticism','epistemology','logic'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('appearances-life','Following appearances without dogmatic commitment',[
      'The familiar objection says skeptics cannot live: eating, avoiding danger, practicing medicine, and speaking seem to require belief. Sextus replies that the skeptic follows appearances without asserting how things are by nature. Life proceeds through natural capacities, bodily feelings, inherited customs and laws, and instruction in arts. Hunger prompts eating, an apparent obstacle prompts avoidance, and medical symptoms invite practiced responses. None requires a theory guaranteeing ultimate truth.',
      'Whether this counts as life without belief depends on the meaning of belief. Sextus often reserves dogma for assent to non-evident theoretical claims, leaving room for ordinary acceptance or passive acquiescence to appearances. Critics argue that deliberate action and language involve stronger commitments than he admits. The debate reveals a lasting skeptical insight: practical confidence can be graded and revisable. A person may act responsibly on evidence without pretending that action converts a fallible judgment into knowledge of underlying nature.',
      'Sextus groups the guidance of life under four headings: nature, the compulsion of feelings, customs and laws, and teaching in practical arts. The list prevents skepticism from being mistaken for paralysis, but it also exposes difficult cases. Customs conflict, expertise can be contested, and immediate feelings may mislead. The skeptic still has to navigate these pressures without an ultimate criterion. This makes ordinary life not an escape from philosophy but the setting in which non-dogmatic responsiveness is tested, corrected, and sometimes left unresolved.'
    ],['skepticism','ethics','epistemology'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('rivals','Stoics, Epicureans, Platonists, and Aristotelians',[
      'Sextus draws heavily on disputes among dogmatic schools. Against Stoics, skeptics challenge the cognitive impression, signs, proof, providence, and the claim that the sage possesses knowledge. Against Epicureans, they question whether sensation securely supports inference to atoms and void. Platonist and Aristotelian accounts of forms, causes, demonstration, and ethical ends also supply targets. Sextus often places one school’s arguments against another rather than building an independent rival system.',
      'This method makes skepticism intellectually dependent on the traditions it criticizes, but not empty. The skeptic must understand an argument well enough to reveal its unsupported transitions and locate an opposing case. Competing systems become resources for testing each other. The resulting practice resists the assumption that philosophical disagreement is solved by choosing the most attractive comprehensive picture. It asks whether the reasons offered actually warrant that choice, and whether confidence survives comparison with alternatives.'
    ],['skepticism','stoicism','epicureanism','platonism','aristotelianism'],['sextus-empiricus','zeno','epicurus','plato','aristotle'],[]),
    section('therapy-denialism','Therapy rather than denialism',[
      'Sextan skepticism is therapeutic because dogmatic judgments can intensify disturbance. A person not only feels pain but judges pain to be an absolute evil; not only lacks fame but believes fame necessary for happiness; not only encounters disagreement but demands immediate final settlement. Counterarguments weaken the grip of these judgments, and tranquility may follow suspension unexpectedly. Unavoidable feelings remain, but they are no longer multiplied by claims about what must be feared or pursued.',
      'This has nothing in common with denialism that dismisses strong evidence for convenience, identity, or power. Denialism selectively raises standards against unwelcome conclusions while leaving favored claims untouched. The Pyrrhonist turns scrutiny in every direction, including toward skeptical formulas and personal preferences. Nor is therapy an excuse to ignore consequences. Sextus’ skeptic follows appearances, skills, and ordinary life. The target is not responsible responsiveness but the unsupported theoretical certainty that presents itself as necessary for action.'
    ],['skepticism','ethics','epistemology'],['sextus-empiricus'],[]),
    section('self-refutation','Can skepticism survive its own arguments?',[
      'The self-refutation objection asks whether the skeptic asserts that no assertion is justified, knows that knowledge is impossible, or uses logic to destroy logic. Any such universal claim appears to undermine itself. Sextus anticipates the problem by treating skeptical expressions as reports of present appearances rather than doctrines. They are compared to purgative medicines that remove themselves along with what they treat or to a ladder no longer needed after use.',
      'The response is ingenious but contested. Writing a sustained book seems to require stable meanings, inferential practices, memory, and confidence that some arguments are appropriate. If these are merely followed non-dogmatically, critics ask what distinguishes responsible skeptical practice from unaccountable persuasion. Sextus’ importance partly lies in keeping this problem alive. He shows how difficult it is to criticize standards without relying on standards, while refusing to let that difficulty automatically validate whatever dogmatic theory happens to be available.',
      'One productive reading distinguishes using a practice from giving a final theory of its authority. Sextus can reason, remember, and communicate as these activities presently function without claiming to have established their nature or ultimate foundation. That distinction resembles ordinary fallibilism, but Pyrrhonism pushes further by withholding even a settled doctrine of fallibility. Whether this position is coherent remains disputed. The dispute is valuable because it forces both skeptic and critic to specify how much commitment successful inquiry requires, rather than assuming that any use of reason entails a comprehensive theory of reason.'
    ],['skepticism','logic','epistemology'],['sextus-empiricus'],['Outlines of Pyrrhonism']),
    section('revival','Renaissance recovery and early modern transformation',[
      'Sextus’ works became newly influential in Renaissance and early modern Europe as Greek texts circulated and Latin translations appeared. Montaigne drew on skeptical arguments to challenge presumption, examine custom, and complicate claims about human reason. Religious controversy gave ancient disputes about criteria and disagreement new urgency: if authorities and interpreters conflict, what could settle their claims without begging the question?',
      'Descartes transformed skeptical doubt into a method aimed at discovering certainty, a goal unlike Pyrrhonian suspension. Hume used skeptical arguments about causation, induction, self, and reason while describing how natural habits return people to ordinary life. Later epistemology continues to answer challenges concerning criteria, regress, disagreement, perception, and the possibility of knowledge. These receptions often turn Sextus into an opponent to refute, but his own practice asks a prior question: why must inquiry promise the kind of certainty the refutation seeks?'
    ],['skepticism','epistemology','rationalism','empiricism'],['sextus-empiricus','descartes','hume'],['Outlines of Pyrrhonism','Meditations on First Philosophy']),
    section('reading','How to read Sextus Empiricus',[
      'Begin with Book I of the Outlines of Pyrrhonism. Track the differences among inquiry, assertion, appearance, suspension, and tranquility before moving to the arguments against logic, physics, and ethics. Notice when Sextus borrows premises for dialectical use rather than endorsing them. Then read selections from Against the Mathematicians to see skeptical practice directed at specialized disciplines and to appreciate how much earlier philosophy survives through his reports.',
      'Keep several misunderstandings in view. Pyrrhonism is not the doctrine that nothing is true, not indifference to evidence, and not a performance of doubt used to avoid responsibility. Its formulas remain provisional, its inquiry continues, and its practical life follows appearances and skills. The most productive reading lets Sextus pressure both dogmatic confidence and skeptical ease. Ask what warrants assent, but also ask what the skeptic must already be doing in order to ask successfully.'
    ],['skepticism','epistemology'],['sextus-empiricus','pyrrho','descartes','hume'],['Outlines of Pyrrhonism','Against the Mathematicians'])
  ],
  lucretius:[
    section('overview','Epicurean philosophy made into a Roman poem',[
      'Lucretius is known almost entirely through De Rerum Natura, a six-book Latin poem that presents Epicurean physics as therapy for fear, desire, and superstition. The poem explains atoms and void, perception and mind, mortality and cosmic formation, sexuality and civilization, weather and plague. These subjects belong together because mistaken pictures of nature make people vulnerable to terror and unlimited ambition. Natural explanation can free a reader only if it reaches imagination and emotion as well as abstract judgment.',
      'Lucretius therefore matters as a philosophical poet, not simply a translator of Epicurus into verse. He addresses a Roman reader, Memmius, invokes divine beauty while denying divine government, and uses analogy, rhythm, vivid scenes, and argumentative pressure to make imperceptible atoms intelligible. The poem’s pleasures are part of its method. Honey on the rim of a medicinal cup becomes an image for poetry carrying difficult doctrine, yet the poetry also tests and transforms the philosophy it communicates.'
    ],['epicureanism','ancient-greek','aesthetics'],['lucretius','epicurus'],['On the Nature of Things']),
    section('biography-context','An obscure life in the late Roman Republic',[
      'Reliable information about Lucretius’ life is extremely limited. He probably lived during the first century BCE and wrote amid the political violence and social instability of the late Roman Republic. Later biographical reports include dramatic stories about madness, a love potion, and suicide, but these are late, hostile, and often treated with skepticism. The poem itself provides evidence of education, philosophical commitment, literary ambition, and concern with Roman power, but it is not a transparent autobiography.',
      'The political setting gives force to Epicurean criticism of ambition. Competition for office, military glory, wealth, and public recognition promised security while producing fear and conflict. Lucretius repeatedly observes people struggling for status as though climbing a dangerous height, then falling or envying those above them. His response is not a direct constitutional program. It is an attack on the desires and beliefs that make domination attractive. Understanding nature exposes how little rank can do against mortality and how much suffering arises from demands with no natural limit.'
    ],['epicureanism','political-philosophy','ancient-greek'],['lucretius','epicurus'],['On the Nature of Things']),
    section('poetry-therapy','Poetry, argument, and philosophical therapy',[
      'De Rerum Natura opens by invoking Venus as the generative force and pleasure of life, then asks for peace in a world marked by war. The invocation can surprise readers expecting a materialist attack on religion. Lucretius uses inherited poetic language while redirecting it: divine imagery evokes natural generation and aesthetic attraction without establishing providential control. The poem must work within the reader’s imagination before it can free that imagination from terrifying stories.',
      'The famous image of coating a medicine cup with honey explains why verse carries difficult Epicurean teaching. Yet Lucretius’ poetry does more than sweeten a fixed message. Vivid descriptions of storms, desire, disease, sacrifice, and infinite worlds show how language constructs fear and how alternative descriptions can change it. Repetition serves philosophical rehearsal, while scale shifts from dust motes to cosmic infinity loosen ordinary assumptions. The reader is not merely informed that nature is material; the poem trains a different way of seeing.',
      'That training often begins from familiar appearances. Dust motes moving in a beam of light offer an analogy for unseen atomic motion; worn rings and paving stones make imperceptible material loss imaginable; recurring generations show stable forms arising from changing matter. Analogies do not function as modern experimental proofs, and Lucretius knows that invisible causes require argument. Their purpose is to connect reasoning with perception so a reader can inhabit the explanation. Philosophy succeeds therapeutically only when the old frightening picture no longer monopolizes what the world feels like.'
    ],['epicureanism','aesthetics','philosophy-of-language'],['lucretius','epicurus'],['On the Nature of Things']),
    section('atoms-void','Atoms, void, and a world without supernatural rule',[
      'Lucretius argues that nothing comes from nothing and nothing is reduced to nothing. Invisible, indivisible bodies move through void, combining into perceptible compounds that arise, change, and dissolve. Differences in atomic shape, arrangement, motion, and combination explain the variety of things without appealing to creation from nothing or purposes imposed by gods. Void is required for motion, while the persistence of basic matter explains why dissolution does not become absolute annihilation.',
      'This physics is ethically charged. Thunder, eclipses, disease, and disaster become terrifying when interpreted as divine messages or punishments. Showing that natural processes have natural causes removes the authority of those who trade in fear. Lucretius does not always insist on one explanation for distant phenomena; several natural accounts can be sufficient when evidence cannot decide among them. The therapeutic victory lies in excluding supernatural terror, not pretending to certainty beyond what appearances support.',
      'The universe has no privileged center or enclosing boundary in this account. Matter and void extend without limit, and innumerable combinations can produce worlds unlike this one. Human history therefore occupies neither the purpose nor the permanent center of nature. This displacement can initially intensify anxiety, yet Lucretius presents it as liberation from cosmic surveillance and exceptionalism. Finitude becomes ordinary within an inexhaustible material process. The difficult ethical lesson is that significance need not depend on the universe being arranged for human beings or preserving them forever.'
    ],['epicureanism','metaphysics','philosophy-of-science'],['lucretius','epicurus','democritus'],['On the Nature of Things']),
    section('swerve','The atomic swerve and agency within nature',[
      'Lucretius describes atoms deviating by a minimal, indeterminate amount from their downward motion. Without this swerve, parallel atoms would never collide to form worlds, and every motion would follow from an unbroken chain. The passage also connects the swerve with the ability of living beings to initiate motion rather than being driven only by external impact. It has therefore become central to debates about Epicurean freedom.',
      'The swerve is not a complete theory of responsible agency. Randomness alone would not produce rational choice, and scholars dispute how the physical deviation relates to volition. Its importance lies partly in resisting a picture of nature as either providentially planned or mechanically fatalistic. Lucretius wants human action to belong fully within material nature without becoming merely passive consequence. The difficulty anticipates modern problems about freedom, causation, and whether indeterminacy helps explain agency.',
      'The passage should also be read within Epicurean therapy. If every motion, desire, and decision were experienced as the inevitable result of a chain extending beyond control, ethical training could appear pointless. Lucretius needs enough openness for deliberation and habituation to matter, while keeping agency inside nature. The swerve marks that requirement at the physical level without explaining all the psychological capacities through which a person evaluates desires, remembers instruction, and changes a life. It protects the possibility of self-direction without turning human beings into exceptions to the material order the poem has worked to establish.'
    ],['epicureanism','metaphysics','ethics'],['lucretius','epicurus'],['On the Nature of Things']),
    section('perception-mind','Perception, mind, and the mortal soul',[
      'Lucretius explains perception through material interactions. Thin films or images from objects strike the senses, while sound, smell, and taste also depend on bodily processes. Sensation supplies contact with the world; error enters when judgment adds an unsupported interpretation. Dreams, optical effects, and changing appearances can be explained without concluding that perception itself is useless. Reason depends on sensory evidence and cannot coherently invalidate its own foundation.',
      'Mind and soul are bodily, composed of especially fine matter distributed through the living organism. They develop with the body, are affected by illness and injury, and disperse at death. This argument opposes Platonic immortality and removes the imagined subject who might suffer eternal punishment. It also gives Lucretius a demanding task: explain thought, emotion, and agency materially without treating them as unreal. His account is ancient and scientifically superseded, but the project remains recognizable in debates about consciousness and naturalism.'
    ],['epicureanism','epistemology','philosophy-of-mind'],['lucretius','epicurus','plato'],['On the Nature of Things']),
    section('death-superstition','Death, sacrifice, and the critique of superstition',[
      'The poem repeatedly argues that death is nothing to us because experience ends when the soul-body compound dissolves. Lucretius uses a symmetry argument: people do not suffer from the infinite time before birth, so the endless time after death need not terrify them. He exposes fantasies in which a person imagines witnessing their own absence, mourning lost possessions, or enduring deprivation while no subject remains to experience it.',
      'Fear of death feeds superstition and ambition. Lucretius’ account of the sacrifice of Iphigenia presents religion driving a father and army toward atrocity under the promise of divine favor. The critique targets practices and stories that convert fear into obedience, not every experience of wonder or reverence. By explaining nature without providential punishment, the poem seeks to remove a political and psychological instrument of domination. Mortality becomes a limit within which life can be enjoyed rather than a threat requiring power, fame, or ritual appeasement.'
    ],['epicureanism','philosophy-of-religion','ethics'],['lucretius','epicurus'],['On the Nature of Things']),
    section('pleasure-desire','Pleasure, desire, friendship, and the view from safety',[
      'Lucretius presents Epicurean pleasure as bodily ease and mental tranquility rather than continuous indulgence. One famous passage imagines watching a storm at sea from safety, not because another person’s suffering is pleasant, but because the contrast reveals freedom from the turmoil created by false beliefs. Philosophy offers a secure vantage from which ambition, fear, and rivalry become visible as avoidable forms of disturbance.',
      'The poem analyzes sexual desire with particular severity, distinguishing bodily pleasure from obsessive projections that turn another person into an impossible cure for longing. Natural desires can be satisfied, while fantasies of possession renew themselves. Friendship and Epicurean community are less prominent dramatically than in some surviving Epicurean sayings, but the poem itself enacts intellectual friendship by addressing Memmius and honoring Epicurus as a liberator. Teaching becomes an effort to share freedom rather than monopolize it.'
    ],['epicureanism','ethics'],['lucretius','epicurus'],['On the Nature of Things']),
    section('civilization','Worlds, human history, and naturalized civilization',[
      'Lucretius describes a universe containing innumerable worlds that arise and perish through material processes. Earth is not an eternal stage designed for humanity, and its capacities can decline. Human beings also develop historically: early lives, language, fire, cooperation, property, law, religion, warfare, and art emerge without a single divine legislator. This naturalized history explains institutions as contingent achievements and dangers rather than fixed expressions of cosmic purpose.',
      'Civilization brings security and invention while multiplying artificial desires, hierarchy, and violence. Lucretius does not simply praise an imagined primitive life, since early humans faced exposure and danger. He instead asks which developments reduce pain and which create new dependency. The account supports Epicurean limits: technological and political power cannot satisfy desires whose measure remains comparison. Progress in control over nature may coexist with intensified fear unless understanding also transforms what people seek.'
    ],['epicureanism','political-philosophy','philosophy-of-science'],['lucretius','epicurus'],['On the Nature of Things']),
    section('plague','The plague ending and an unsettled therapeutic poem',[
      'De Rerum Natura ends with a devastating description of plague at Athens. Bodies suffer, medical knowledge fails, social practices collapse, and fear overwhelms ritual and obligation. The ending has generated lasting dispute. Some readers think the poem was unfinished; others see a deliberate test of whether Epicurean understanding can withstand extreme suffering. The closing darkness contrasts sharply with the opening invocation of generative Venus.',
      'The plague prevents therapy from appearing effortless. Natural explanation can remove divine terror without preventing disease or grief. People who understand mortality still face pain, while communities can break under collective crisis. The ending may reveal what happens when fear remains untrained or may ask readers to supply the philosophical response the narrative withholds. Its refusal of easy consolation gives the poem unusual honesty: materialism promises freedom from false fears, not a world in which material bodies cannot be destroyed.',
      'The episode also tests the relation between individual tranquility and shared institutions. Burial customs fail, competition for safety intensifies, and exhausted caregivers become vulnerable through service. A philosophy concerned only with a private state of mind would have little to say about these scenes. Lucretius instead leaves readers facing the social consequences of embodied dependence. Naturalism can explain contagion and remove fantasies of punishment, but communities still need practices of care under pressure. The abrupt close keeps that problem open rather than converting catastrophe into a neat demonstration of doctrine.'
    ],['epicureanism','ethics','philosophy-of-science'],['lucretius','epicurus'],['On the Nature of Things']),
    section('reception-reading','Rediscovery, influence, and how to read Lucretius',[
      'Lucretius had ancient readers but became dangerous or suspect within traditions opposed to Epicurean mortality and non-providential nature. The poem survived through manuscripts and was famously recovered into wider circulation during the Renaissance. Its atomism, critique of superstition, account of mortality, and poetic power entered early modern debates about nature, religion, science, and materialism. Later writers have read it as philosophy, literature, secular provocation, and a model of how explanatory imagination can change emotion.',
      'Begin with Books I and III to encounter atoms, void, mind, soul, and death, then read the complete poem so its cosmology, desire, civilization, and plague ending remain connected. Compare Lucretius with Epicurus’ letters to see where the poet elaborates, dramatizes, or shifts the teaching. Do not strip the arguments from the verse or treat the poetry as decoration. Lucretius matters because he asks whether a material explanation can become vivid enough to compete with the stories through which fear ordinarily understands the world.'
    ],['epicureanism','aesthetics','philosophy-of-science'],['lucretius','epicurus'],['On the Nature of Things'])
  ]
};

export const hellenisticFoundationBranchArticles:Record<string,ArticleSection[]>={
  cynicism:[
    section('overview','Philosophy performed against artificial need',[
      'Ancient Cynicism was a provocative philosophical way of life organized around freedom, virtue, nature, and the exposure of convention. Cynics reduced material needs, trained endurance, rejected status, and used public speech and performance to show how ordinary respectability depends on fear and artificial desire. Their philosophy survives less through systematic treatises than through anecdotes, sayings, encounters, and later reports. The form is appropriate: Cynicism aimed to make arguments visible in a life that interrupted the city’s habits.',
      'Calling Cynicism ancient minimalism misses its severity and public purpose. Owning little was not primarily an aesthetic preference or private efficiency strategy. Poverty and askesis tested whether wealth, housing, citizenship, reputation, and social permission were necessary for freedom. Shameless acts challenged conventions that claimed natural authority. At its best, Cynicism asks whether a society’s honored needs are instruments of dependence. At its worst or in imitation, provocation can become spectacle without discipline, responsibility, or a clear target.'
    ],['cynicism','ethics','ancient-greek'],['antisthenes','diogenes','zeno'],[]),
    section('sources-origins','A tradition reconstructed through contested origins',[
      'Cynicism’s origins are difficult to reconstruct because surviving sources are late and anecdotal. Antisthenes, a follower of Socrates, is often presented as a predecessor or founder, while Diogenes of Sinope becomes the tradition’s defining figure. Ancient succession stories connect Socrates to Antisthenes, Diogenes, Crates, and Zeno, creating a lineage that gives Stoicism a Cynic ancestry. Historians debate how closely this neat chain reflects actual teacher-student relations.',
      'The source problem does not make Cynicism unreal, but it changes how its philosophy is read. A story about Diogenes may have been invented or polished to express a Cynic stance. Repeated themes across anecdotes reveal a recognizable repertoire: frank speech, contempt for luxury, reversal of shame, self-sufficiency, and freedom before rulers. Readers should ask not only whether an encounter happened exactly as told, but what social assumption the story is designed to expose and why later audiences preserved it.'
    ],['cynicism','ancient-greek','stoicism'],['antisthenes','diogenes','zeno'],[]),
    section('antisthenes','Antisthenes and the Socratic inheritance',[
      'Antisthenes studied with Socrates and emphasized virtue, endurance, and independence from external goods. Surviving reports associate him with the claim that virtue can be taught and is sufficient for happiness, requiring deeds rather than elaborate words. His exact relation to later Cynicism remains contested, partly because his own intellectual interests were broader than the simplified founder portrait suggests. Still, he represents a route from Socratic examination toward disciplined self-sufficiency.',
      'The Socratic inheritance gives Cynicism moral seriousness beneath its comic and scandalous surface. Socrates lived simply, questioned prestigious experts, accepted poverty, and refused to make survival the highest good. Cynics radicalized these features into a public rejection of convention. Yet Socratic dialogue and civic engagement do not map perfectly onto Cynic performance. The relation is best understood as transformation: the examined life becomes an embodied challenge in which possessions, habits, and shame are tested as claims about what goodness requires.'
    ],['cynicism','ethics'],['antisthenes','socrates','diogenes'],['Apology','Memorabilia']),
    section('diogenes','Diogenes and philosophy as public counterexample',[
      'Diogenes of Sinope is remembered through stories of homelessness, a storage jar or tub, a lamp carried in daylight while searching for an honest human being, confrontations with Plato, and refusal to flatter Alexander. These scenes make him a counterexample to the assumption that power and possessions command respect. When Alexander supposedly offers a favor, Diogenes asks him to move out of the sunlight. The anecdote compresses Cynic freedom: the ruler has nothing the philosopher needs and can only obstruct what nature freely provides.',
      'Diogenes’ performances use comedy, insult, and reversal to make audiences recognize their own dependence. Public actions considered shameless challenge the division between natural bodily needs and conventions enforced through embarrassment. Such provocations can be ethically troubling and were designed to offend. Their philosophical test is whether the broken convention protects genuine goods or merely maintains hierarchy and pretense. Diogenes does not argue that every norm is false; he forces spectators to explain why a norm deserves obedience.'
    ],['cynicism','political-philosophy','ethics'],['diogenes','plato','zeno'],[]),
    section('crates-hipparchia','Crates, Hipparchia, and a shared Cynic life',[
      'Crates of Thebes reportedly gave up substantial wealth and became a Cynic teacher whose gentler public manner earned affection. He taught Zeno and helped transmit Cynic independence into early Stoicism. Crates shows that Cynic provocation need not take only Diogenes’ abrasive form. Renunciation can become instruction, and freedom from possession can create a life available for public philosophical service rather than competitive accumulation.',
      'Hipparchia of Maroneia chose a Cynic life with Crates despite family opposition and the gender expectations of Greek society. Ancient reports portray her appearing publicly, debating, and rejecting the confinement expected of respectable women. The evidence is limited and filtered by later fascination, but her presence exposes the political reach of Cynic appeals to nature. If conventional roles create artificial dependency, gendered restrictions require criticism too. Hipparchia demonstrates that the Cynic rejection of status could challenge not only wealth and citizenship but the organization of philosophical participation itself.'
    ],['cynicism','stoicism','feminist-philosophy'],['zeno'],[]),
    section('askesis','Askesis, poverty, and trained freedom',[
      'Cynic askesis is training designed to reduce vulnerability to fortune and social control. Exposure to heat or cold, simple food, limited possessions, and endurance of discomfort reveal which needs are natural and which have been cultivated by habit. Voluntary hardship is not valuable because suffering is good. It tests capacities and makes the philosopher less easily coerced by threats of deprivation or promises of luxury.',
      'Poverty in Cynicism is therefore both material practice and public argument. A person who can live with little demonstrates that wealth is not necessary for virtue. Yet romanticizing poverty is dangerous, especially when voluntary simplicity is confused with deprivation imposed on others. The Cynic chooses training as a route to agency; people denied food, shelter, or safety do not thereby receive philosophical freedom. Modern appropriation must distinguish critique of artificial need from indifference to preventable suffering.',
      'Training also reveals that freedom is a maintained capacity rather than a single decision to renounce. Habits of appetite, comfort, approval, and comparison return because social life continually rewards them. Repeated exercises make the distinction between use and dependence visible: a Cynic may use a cloak, food, or shelter while testing whether losing it would destroy the ability to act well. This practical emphasis separates Cynicism from merely holding radical opinions. The claim that virtue is sufficient acquires force only when a life has been shaped to withstand the pressures that ordinarily make the claim seem impossible.'
    ],['cynicism','ethics','stoicism'],['diogenes','zeno'],[]),
    section('nature-convention','Nature, convention, and shamelessness',[
      'Cynics oppose nature, physis, to convention, nomos, but the contrast is not a complete theory with an easy list of natural rules. It is a critical question directed at practices that command obedience through habit and shame. Why should wealth prove worth, citizenship limit moral concern, or respectable appearance conceal vice? By stripping away social decoration, Cynics seek a life whose needs and actions can be defended without appeal to reputation.',
      'Shamelessness, anaideia, becomes a method because shame polices convention before argument begins. Publicly performing ordinary bodily functions or refusing expected deference exposes how power inhabits embarrassment. The method can liberate, but it can also become aggression that ignores the dignity of others. Cynic shamelessness has philosophical value when it reveals artificial domination and accepts personal cost, not when provocation merely transfers humiliation onto a target with less power.'
    ],['cynicism','ethics','political-philosophy'],['diogenes','antisthenes'],[]),
    section('freedom-speech','Frank speech, self-sufficiency, and freedom before power',[
      'Cynic freedom depends on parrhesia, frank speech, and autarkeia, self-sufficiency. A person who needs favors, office, or applause cannot easily tell powerful people the truth. Reducing dependence makes speech less vulnerable to retaliation. Cynic encounters with rulers dramatize this relation: the philosopher’s authority comes not from institution or wealth but from having less to lose and from visibly refusing the values through which rulers purchase submission.',
      'Self-sufficiency does not require total isolation. Crates and Hipparchia lived a shared philosophical life, and Cynics taught through public encounter. The ideal concerns freedom from servile need rather than absence of relation. Frank speech also creates responsibilities. Insult alone is not truth, and independence does not guarantee good judgment. The Cynic must show that provocative speech diagnoses a real dependency and arises from disciplined concern rather than vanity disguised as rebellion.',
      'Because Cynic argument is performed before an audience, its success cannot be measured only by the speaker feeling fearless. A confrontation should expose the structure of flattery, status, or manufactured desire so that witnesses can recognize it in themselves. The risk is that memorable insolence overshadows the ethical diagnosis and turns the Cynic into another celebrity. Ancient worries about counterfeit Cynics arise here. Parrhesia needs independence, but it also needs accuracy, courage about consequences, and a purpose beyond attention. Otherwise the performance reproduces the economy of reputation it claims to reject.'
    ],['cynicism','ethics','political-philosophy'],['diogenes'],[]),
    section('cosmopolitanism','Citizenship, exile, and the world as a community',[
      'Diogenes is associated with calling himself a citizen of the world, a cosmopolitan. The phrase challenges the idea that identity and obligation are exhausted by one city, legal status, or inherited community. For a displaced person from Sinope, it also transforms exclusion into a claim to broader belonging. Cynic cosmopolitanism is less a detailed program of global institutions than a refusal to let civic privilege define human worth.',
      'The claim influenced Stoicism, which developed a more systematic account of rational beings sharing one moral community. Cynic cosmopolitanism remains sharper and less institutionally comfortable: if the world is the community, local honors and boundaries lose some authority. Yet a declaration of world citizenship can become abstract if it neglects concrete duties and unequal power. The enduring challenge is to connect freedom from parochial status with responsible relation to actual people rather than using universality as another form of detachment.',
      'Cosmopolitan speech also changes the meaning of exile. A city can remove legal standing, property, and participation, but it cannot make virtue impossible if the world remains available as the field of action. This reversal turns a civic punishment into criticism of the city that treats belonging as a privilege it owns. Still, material exclusion remains real, and the Cynic response does not erase its harms. The provocation works by showing that political authorities control important conditions without controlling the whole measure of a human life.'
    ],['cynicism','stoicism','political-philosophy'],['diogenes','zeno','marcus-aurelius'],[]),
    section('rival-paths','Stoic discipline and Epicurean withdrawal',[
      'Stoicism inherits Cynic claims that virtue is sufficient and convention often corrupts desire. Through Crates and Zeno, Cynic independence becomes part of a system joining logic, physics, ethics, preferred indifferents, and social roles. Stoics can participate in institutions and select health or resources while denying that these determine moral worth. Cynics remain more suspicious that such distinctions permit compromise and renewed dependence.',
      'Epicureans also criticize ambition and artificial desire, but build communities of friendship and withdraw from corrosive competition rather than making provocation central. Epicurean simplicity aims at tranquility through natural explanation and secure association. Cynic poverty publicly confronts the city and exposes its values through performance. Both challenge luxury, yet their social styles differ: the Garden creates an alternative community, while the Cynic turns streets, marketplaces, and encounters with power into a philosophical stage.'
    ],['cynicism','stoicism','epicureanism'],['diogenes','zeno','epicurus'],[]),
    section('reception-misreadings','Reception and modern misunderstandings',[
      'Ancient Cynicism influenced Stoicism and remained visible through wandering preachers, satirists, and public moral critics. Some later figures adopted the costume and aggression without the discipline, prompting complaints about counterfeit Cynics. Christian ascetic traditions could find affinities in poverty and frank speech while rejecting Cynic shamelessness and theology. Modern language transformed “cynicism” into distrust of motives and expectation of corruption, nearly the opposite of ancient Cynic confidence that virtue can free a person from social falsehood.',
      'Ancient Cynicism is also misread as anti-social behavior, performative rebellion, or lifestyle minimalism. Mere rudeness remains dependent on an audience, and rebellion that cannot explain its target is another performance of status. Owning fewer objects does not by itself create virtue. Cynic practice joins reduction of need to courage, frankness, and an argument about nature and convention. Its challenge is ethical: can a person expose false values without reproducing cruelty, vanity, or disregard for those who bear involuntary hardship?'
    ],['cynicism','stoicism','ethics'],['diogenes','zeno'],[]),
    section('reading','How to start reading Cynicism',[
      'No single surviving Cynic treatise provides an authoritative system. Begin with carefully annotated collections of anecdotes and fragments concerning Antisthenes, Diogenes, Crates, and Hipparchia. Read each story as both possible historical evidence and a crafted philosophical scene. Ask which convention is being challenged, what freedom the Cynic displays, who bears the cost of the performance, and whether the action expresses trained virtue or only shock.',
      'Then compare Cynic material with Socratic sources and early Stoicism. Socrates clarifies the moral seriousness behind examination and simplicity; Zeno shows how Cynic independence enters a broader system; Epictetus reveals later debate about the true Cynic’s demanding social mission. Keep modern cynicism separate from the ancient school. The central question is not whether people are secretly selfish. It is whether artificial needs and fears have made a life unfree, and what kind of disciplined public counterexample could reveal that dependence.'
    ],['cynicism','stoicism','ethics'],['antisthenes','diogenes','zeno','epictetus'],['Apology','Memorabilia','Discourses'])
  ]
};
